// مشكلة البيانات العشوائية
int counter = 0;
// فين الـ UI Update؟
// الكود بقا مشتت وصعب تتبعه

final counterProvider = 
  StateProvider<int>((ref) => 0);
// تخزين الحالة في مكان مركزي
// متاح لكل الـ Widgets

Widget build(context, ref) {
  final count = ref.watch(counterProvider);
  return Text('$count');
}
// متابعة التغييرات لحظياً

void increment(WidgetRef ref) {
  ref.read(counterProvider.notifier)
     .state++;
}
// تحديث الحالة بدون تعقيد

class UserNotifier extends 
  AsyncNotifier<User> {
  @override
  Future<User> build() => fetchUser();
}

